parameters.text:
You are a certified personal trainer and sports scientist. Analyze this workout log and return ONLY valid JSON (no markdown, no extra text):

Workout description: {{ $json['What did you do today?'] }}
Duration: {{ $json['Duration (minutes)'] }} minutes
Feeling: {{ $json['How do you feel? (1-10)'] }}
Notes: {{ $json['Notes'] || 'None' }}

Return this exact JSON structure:
{
  "exercises": [
    {
      "name": "Exercise name",
      "type": "strength/cardio/flexibility/other",
      "muscle_groups": ["primary muscles worked"],
      "sets": 0,
      "reps": 0,
      "weight_kg": 0,
      "duration_min": 0,
      "estimated_calories": 0
    }
  ],
  "summary": {
    "total_exercises": 0,
    "total_calories": 0,
    "primary_type": "strength/cardio/mixed",
    "muscle_groups_hit": ["list of all muscles worked"],
    "intensity": "low/moderate/high/very high"
  },
  "tips": [
    "One specific, actionable tip based on this workout",
    "Another tip about recovery or next session"
  ],
  "next_workout_suggestion": "Brief suggestion for complementary workout"
}

parameters.jsCode:
// Parse and validate AI workout analysis
const aiResponse = $json.response || $json.text || '';

// Extract JSON from response
let jsonStr = aiResponse;
const jsonMatch = aiResponse.match(/```(?:json)?\s*([\s\S]*?)```/);
if (jsonMatch) {
  jsonStr = jsonMatch[1].trim();
}

let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  parsed = {
    exercises: [],
    summary: {
      total_exercises: 0,
      total_calories: 0,
      primary_type: 'unknown',
      muscle_groups_hit: [],
      intensity: 'moderate'
    },
    tips: ['Could not parse workout details. Try being more specific next time.'],
    next_workout_suggestion: 'Rest day or light cardio'
  };
}

// Get original form data
const form = $('Workout Log Form').first().json;
const feelingRaw = form['How do you feel? (1-10)'] || '5';
const feeling = parseInt(feelingRaw.match(/\d+/)?.[0] || '5');

return {
  date: new Date().toISOString().split('T')[0],
  workout_description: form['What did you do today?'],
  duration_min: parseInt(form['Duration (minutes)']) || 0,
  feeling: feeling,
  notes: form['Notes'] || '',
  exercises: parsed.exercises || [],
  exercise_count: (parsed.exercises || []).length,
  total_calories: parsed.summary?.total_calories || 0,
  primary_type: parsed.summary?.primary_type || 'unknown',
  muscle_groups: (parsed.summary?.muscle_groups_hit || []).join(', '),
  intensity: parsed.summary?.intensity || 'moderate',
  tips: (parsed.tips || []).join(' | '),
  next_suggestion: parsed.next_workout_suggestion || '',
  logged_at: new Date().toISOString()
};

// Build a nice summary for notifications
const w = $json;

// Emoji for feeling
const feelEmoji = w.feeling >= 8 ? '🔥' : w.feeling >= 5 ? '💪' : '😤';

// Emoji for type
const typeEmoji = {
  'strength': '🏋️',
  'cardio': '🏃',
  'mixed': '🏋️🏃',
  'flexibility': '🧘'
};
const tEmoji = typeEmoji[w.primary_type] || '💪';

const intensityBar = {
  'low': '🟢',
  'moderate': '🟡',
  'high': '🟠',
  'very high': '🔴'
};
const iBar = intensityBar[w.intensity] || '🟡';

const slackMsg = [
  `${tEmoji} *Workout Logged* — ${w.date}`,
  ``,
  `*What:* ${w.workout_description}`,
  `*Duration:* ${w.duration_min} min | *Feeling:* ${w.feeling}/10 ${feelEmoji}`,
  `*Type:* ${w.primary_type} | *Intensity:* ${iBar} ${w.intensity}`,
  `*Calories:* ~${w.total_calories} kcal`,
  `*Muscles:* ${w.muscle_groups}`,
  ``,
  `💡 *Tips:* ${w.tips}`,
  `📋 *Next time:* ${w.next_suggestion}`,
  w.notes ? `📌 ${w.notes}` : ''
].filter(Boolean).join('\n');

const emailHtml = `<h2>${tEmoji} Workout Summary — ${w.date}</h2>
<p><strong>Workout:</strong> ${w.workout_description}<br>
<strong>Duration:</strong> ${w.duration_min} min | <strong>Feeling:</strong> ${w.feeling}/10 ${feelEmoji}<br>
<strong>Type:</strong> ${w.primary_type} | <strong>Intensity:</strong> ${w.intensity}<br>
<strong>Estimated Calories:</strong> ~${w.total_calories} kcal<br>
<strong>Muscle Groups:</strong> ${w.muscle_groups}</p>
<h3>💡 Tips</h3>
<p>${w.tips.replace(/ \| /g, '<br>')}</p>
<h3>📋 Next Workout Suggestion</h3>
<p>${w.next_suggestion}</p>
${w.notes ? '<p><em>Notes: ' + w.notes + '</em></p>' : ''}
<hr>
<p><small>Logged automatically via n8n Workout Tracker</small></p>`;

return {
  ...w,
  slack_message: slackMsg,
  email_html: emailHtml
};
